#!/usr/bin/env python
"""
Bootstrap: Glycan Prediction Set Expansion
  - DGL (Dioclea) scaffold: 4 entries from Chervenak 1995
  - ConA deoxy-glucose series: 5 entries (1 quantitative, 4 NB)
  - ConA fluoro-glucose series: 2 entries
  - ConA maltose + isomaltose: 2 entries
  - Expanded test suite: 30 new tests
  - Updated R2/MAE thresholds for n=31

SUPERSEDES: glycan/contact_maps.py, glycan/scorer.py,
  glycan/tests/test_glycan_scorer.py
ADDS: glycan/tests/test_glycan_expansion.py

Usage: python bootstrap_glycan_expansion.py
  (run from MABE repo root)
"""

import base64, os, sys

# Root detection
if os.path.isfile("core/universal_schema.py"):
    root = "."
elif os.path.isfile(os.path.join("..", "core", "universal_schema.py")):
    root = ".."
    os.chdir(root)
else:
    print("ERROR: Run from MABE repo root (must contain core/universal_schema.py)")
    sys.exit(1)

# Verify glycan module exists
if not os.path.isdir("glycan"):
    print("ERROR: glycan/ directory not found.")
    sys.exit(1)

FILES = {
    'glycan/contact_maps.py': '',
    'glycan/scorer.py': '',
    'glycan/tests/test_glycan_scorer.py': '',
    'glycan/tests/test_glycan_expansion.py': '',
}

for path, b64 in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)
    print(f"  Wrote {path} ({len(content)} bytes)")

print("")
print("Done. Run:")
print("  python -m pytest glycan/tests/ -v")